#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define grep(a,b,c) for(register int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
#define getchar() (p1==p2&&(p2=(p1=buf)+fread(buf,1,1<<19,stdin),p1==p2)?EOF:*p1++)
char buf[1<<21],*p1=buf,*p2=buf;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
void print(int k){if(k>9)print(k/10);putchar(k%10+'0');}
const int N=20005,M=80005,K=1e5+10,INF=0x3f3f3f3f;
int n,m,dis[N],svd,ans[K],VX[N],VY[N];bool vis[N];
struct Graph
{
	int head[N],des[M],val[M],nxt[M],cnt;
	inline void ins(int x,int y,int z){des[++cnt]=y;val[cnt]=z;nxt[cnt]=head[x];head[x]=cnt;}
}a;
struct node{int idx,val;inline bool operator < (const node &x)const{return val>x.val;}};
priority_queue<node> h;inline node Node(int x,int y){node q;q.idx=x;q.val=y;return q;};
struct Query{int x1,x2,y1,y2,idx;}q[K],tmp[K];inline int Cnt(int x,int y){return (x-1)*m+y;}
inline void turn(int q,int &x,int &y){int tmp=q%m;x=q/m+(q%m!=0);y=tmp?tmp:m;}
inline void dij(int s,int x1,int y1,int x2,int y2,bool flag)
{
	int tmp=dis[s];if(flag)rep(x1,x2,i)rep(y1,y2,j)dis[Cnt(i,j)]+=tmp;else memset(dis,0x3f,sizeof(dis));
	memset(vis,0,sizeof(vis));
	h.push(Node(s,dis[s]=0));while(!h.empty())
	{
		node tmp=h.top();h.pop();int u=tmp.idx;
		if(vis[u])continue;vis[u]=1;grep(a,u,i)
		{
			int v=a.des[i],vy,vx;vx=VX[v],vy=VY[v];
			if(x1<=vx&&vx<=x2&&y1<=vy&&vy<=y2)
				if(dis[u]+a.val[i]<dis[v]){dis[v]=dis[u]+a.val[i];h.push(Node(v,dis[v]));}
		}
	}
}
void Solve(int x1,int y1,int x2,int y2,int ql,int qr)
{
	if(ql>qr)return;if(x2-x1>y2-y1)
	{
		int mid=(x1+x2)>>1;rep(y1,y2,i)
		{
			dij(Cnt(mid,i),x1,y1,x2,y2,i^y1);//printf("%d %d:\n",mid,i);
			rep(ql,qr,k)
			{
				ans[q[k].idx]=min(ans[q[k].idx],dis[Cnt(q[k].x1,q[k].y1)]+dis[Cnt(q[k].x2,q[k].y2)]);
//				if(q[k].x1==2&&q[k].y1==1&&q[k].x2==3&&q[k].y2==1)printf("%d\n",ans[q[k].idx]);
//				printf("%d %d\n",q[k].idx,ans[q[k].idx]);
			}
		}
		int l=ql-1,r=qr+1;rep(ql,qr,i)
		{
			if(q[i].x1<mid&&q[i].x2<mid)tmp[++l]=q[i];
			if(q[i].x1>mid&&q[i].x2>mid)tmp[--r]=q[i];
		}
		rep(ql,l,i)q[i]=tmp[i];rep(r,qr,i)q[i]=tmp[i];
		Solve(x1,y1,mid-1,y2,ql,l);Solve(mid+1,y1,x2,y2,r,qr);return;
	}
	int mid=(y1+y2)>>1;rep(x1,x2,i)
	{
		dij(Cnt(i,mid),x1,y1,x2,y2,i^x1);
		rep(ql,qr,k)ans[q[k].idx]=min(ans[q[k].idx],dis[Cnt(q[k].x1,q[k].y1)]+dis[Cnt(q[k].x2,q[k].y2)]);
	}
	int l=ql-1,r=qr+1;rep(ql,qr,i)
	{
		if(q[i].y1<mid&&q[i].y2<mid)tmp[++l]=q[i];
		if(q[i].y1>mid&&q[i].y2>mid)tmp[--r]=q[i];
	}
	rep(ql,l,i)q[i]=tmp[i];rep(r,qr,i)q[i]=tmp[i];
	Solve(x1,y1,x2,mid-1,ql,l);Solve(x1,mid+1,x2,y2,r,qr);
}

int main()
{
//	freopen("1d.txt","r",stdin);freopen("1mm.txt","w",stdout);
	n=read(),m=read();memset(ans,0x3f,sizeof(ans));rep(1,n,i)rep(1,m,j)VX[Cnt(i,j)]=i,VY[Cnt(i,j)]=j;
	rep(1,n,i)rep(1,m-1,j){int u=Cnt(i,j),v=Cnt(i,j+1),z=read();a.ins(u,v,z);a.ins(v,u,z);}
	rep(1,n-1,i)rep(1,m,j){int u=Cnt(i,j),v=Cnt(i+1,j),z=read();a.ins(u,v,z);a.ins(v,u,z);}
	int Q=read();rep(1,Q,i){q[i].x1=read(),q[i].y1=read();q[i].x2=read();q[i].y2=read();q[i].idx=i;}
	Solve(1,1,n,m,1,Q);rep(1,Q,i)print(ans[i]),puts("");return 0;
}
